// 风险等级
export type ubaservicev1_RiskType =
  // 未指定风险类型
  | "RISK_TYPE_UNSPECIFIED"
  // 异常登录风险
  | "RISK_TYPE_LOGIN_ANOMALY"
  // 暴力破解风险
  | "RISK_TYPE_BRUTE_FORCE"
  // 撞库风险
  | "RISK_TYPE_CREDENTIAL_STUFFING"
  // 高频操作风险
  | "RISK_TYPE_FREQUENT_OPERATION"
  // 异常流程风险
  | "RISK_TYPE_ABNORMAL_FLOW"
  // 数据泄露风险
